#nullable enable // autogenerated

using System;
using MVZ2.GameContent.Bosses;
using MVZ2.GameContent.Buffs.Level;
using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Pickups;
using MVZ2.Vanilla.Level;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Definitions;
using UnityEngine;

namespace MVZ2.GameContent.Stages
{
    public abstract class BossStageBehaviour : StageBehaviour
    {
        public BossStageBehaviour(StageDefinition stageDef) : base(stageDef)
        {
        }
        public override void Update(LevelEngine level)
        {
            base.Update(level);
            switch (level.WaveState)
            {
                case VanillaLevelStates.STATE_FINAL_WAVE:
                    FinalWaveUpdate(level);
                    break;
                case VanillaLevelStates.STATE_AFTER_FINAL_WAVE:
                    AfterFinalWaveUpdate(level);
                    break;
                case VanillaLevelStates.STATE_BOSS_FIGHT:
                    BossFightWaveUpdate(level);
                    break;
                case VanillaLevelStates.STATE_AFTER_BOSS:
                    AfterBossWaveUpdate(level);
                    break;
            }
        }
        protected virtual void FinalWaveUpdate(LevelEngine level)
        {
            if (level.HasNoAliveEnemy())
            {
                StartAfterFinalWave(level);
            }
        }
        protected virtual void StartAfterFinalWave(LevelEngine level)
        {
            level.WaveState = VanillaLevelStates.STATE_AFTER_FINAL_WAVE;
            level.PostWaveFinished(level.CurrentWave);
        }
        protected virtual void AfterFinalWaveUpdate(LevelEngine level)
        {

        }
        protected virtual void BossFightWaveUpdate(LevelEngine level)
        {

        }
        protected virtual void AfterBossWaveUpdate(LevelEngine level)
        {
        }
        protected void RunBossWave(LevelEngine level)
        {
            var behaviour = level.GetStageBehaviour<WaveStageBehaviour>();
            if (behaviour != null)
            {
                behaviour.RunBossWave(level);
            }
        }
        protected void ClearEnemies(LevelEngine level)
        {
            foreach (var entity in level.FindEntities(e => e.Type == EntityTypes.ENEMY && !e.IsDead && e.IsHostileEntity()))
            {
                entity.Die(new DamageEffectList(VanillaDamageEffects.NO_REVIVAL));
            }
        }
        protected void EnterLevelEnemiesClearedState(LevelEngine level)
        {
            // 쏵흙濫떱董界榴檄
            if (!level.HasBuff<LevelEnemiesClearedBuff>())
            {
                level.AddBuff<LevelEnemiesClearedBuff>();
            }
        }
        protected void ExitLevelEnemiesClearedState(LevelEngine level)
        {
            // 藁놔濫떱董界榴檄
            level.RemoveBuffs<LevelEnemiesClearedBuff>();
        }
        protected Vector3 GetClearPickupPosition(LevelEngine level, Entity? target)
        {
            Vector3 position;
            if (target != null)
            {
                position = target.Position;
            }
            else
            {
                var x = level.GetLawnCenterX();
                var z = level.GetLawnCenterZ();
                var y = level.GetGroundY(x, z);
                position = new Vector3(x, y, z);
            }
            return position;
        }
        protected Entity? SpawnClearPickup(LevelEngine level, Entity? target)
        {
            Vector3 position = GetClearPickupPosition(level, target);
            return ClearPickup.Produce(level, position);
        }
        protected bool IsHostileBoss(Entity entity)
        {
            return entity.Type == EntityTypes.BOSS && entity.IsHostileEntity();
        }
        protected bool IsAliveHostileBoss(Entity entity)
        {
            return entity.ExistsAndAlive() && IsHostileBoss(entity);
        }
        protected void StartBossTransitionUpdate<T>(LevelEngine level) where T : BuffDefinition
        {
            StartTransitionUntilBossExists<T>(level, () => level.WaveState = VanillaLevelStates.STATE_BOSS_FIGHT);
        }
        protected void StartTransitionUntilBossExists<T>(LevelEngine level, Action onBossExists) where T : BuffDefinition
        {
            if (level.EntityExists(IsAliveHostileBoss))
            {
                onBossExists();
                return;
            }
            if (!level.HasBuff<T>())
            {
                level.AddBuff<T>();
            }
        }
        protected void DisableUIAndInput(LevelEngine level)
        {
            level.ResetHeldItem();
            level.SetUIAndInputDisabled(true);
        }
        protected void StartAfterBossState(LevelEngine level, NamespaceID entityID)
        {
            level.WaveState = VanillaLevelStates.STATE_AFTER_BOSS;
            level.StopMusic();
            if (level.IsFirstAdventure())
            {
                // 占쏙옙占쏙옙UI占쏙옙占쌔깍옙占쏙옙占쏙옙
                DisableUIAndInput(level);
            }
            else
            {
                var reaper = level.FindFirstEntity(entityID);
                SpawnClearPickup(level, reaper);
            }
        }
        protected static void SetBossState(LevelEngine level, int value) => level.SetProperty(FIELD_BOSS_PHASE, value);
        protected static int GetBossState(LevelEngine level) => level.GetProperty<int>(FIELD_BOSS_PHASE);
        private const string PROP_REGION = "boss_stage";
        [LevelPropertyRegistry(PROP_REGION)]
        private static readonly VanillaLevelPropertyMeta<int> FIELD_BOSS_PHASE = new VanillaLevelPropertyMeta<int>("BossPhase");
    }
}
